// Let a USB / console controller BUTTON advance any "press to continue" screen (Briefing, Win,
// Over, Title) — the same screens already accept a tap or keyboard. Polls raw gamepad buttons on an
// interval (works without Phaser's gamepad manager); fires `go` once on a FRESH press after a short
// grace, so the button that ended the previous screen can't instantly skip this one.
function padAdvance(scene, go){
  var t0=scene.time.now, prev=false, fired=false;
  scene.time.addEvent({ delay:55, loop:true, callback:function(){
    if(fired) return;
    var press=false;
    try{ var ps=(navigator.getGamepads?navigator.getGamepads():[]); for(var i=0;i<ps.length;i++){ var gp=ps[i]; if(!gp) continue;
      var B=gp.buttons||[]; for(var j=0;j<B.length;j++){ if(B[j]&&(B[j].pressed||B[j].value>0.5)){ press=true; break; } } if(press) break; } }catch(e){}
    if(press && !prev && (scene.time.now-t0)>500){ fired=true; go(); }
    prev=press;
  }});
}

