/* ---------- Level Select (TEST BUILD only) — jump to any level, no play-through ---------- */
var LevelSelect=new Phaser.Class({ Extends:Phaser.Scene,
  initialize:function(){ Phaser.Scene.call(this,{key:'LevelSelect'}); },
  create:function(){
    var self=this;
    this.cameras.main.setZoom(2).centerOn(W/2,H/2); this.cameras.main.setBackgroundColor(0x0b0a1c);
    this.add.text(W/2,14,'LEVEL SELECT',{fontFamily:'"Press Start 2P"',fontSize:'13px',color:'#ffd23f'}).setOrigin(.5);
    this.add.text(W/2,30,'TEST BUILD · tap any level',{fontFamily:UIFONT,fontStyle:'600',fontSize:'12px',color:'#c3cdf0',resolution:UIRES}).setOrigin(.5);
    // 👑 VIPs get a door to the Lounge (giveaways / alpha / perks) right from the world map
    try{ if(typeof window.__NQ_VIP==='function'&&window.__NQ_VIP()){
      var lg=this.add.text(W-14,13,'👑 VIP LOUNGE',{fontFamily:UIFONT,fontStyle:'bold',fontSize:'11px',color:'#ffd23f',resolution:UIRES}).setOrigin(1,.5).setInteractive({useHandCursor:true});
      lg.on('pointerup',function(){ try{ window.open('/normie-quest-x7/lounge','_blank'); }catch(e){} });
    } }catch(e){}
    // group levels by world (first digit of the "w-n" name), rendered dynamically from LEVELS
    var worlds={}, order=[];
    LEVELS.forEach(function(l,i){ if(l.hidden) return; var w=(l.name||'').split('-')[0]||'?'; if(!worlds[w]){ worlds[w]=[]; order.push(w); } worlds[w].push({l:l,i:i}); });   // hidden bonus levels never show in level-select
    // 12+ worlds outgrew the old shrink-to-fit-on-one-screen approach (rows bottomed out at
    // 20px and overflowed the screen) — fixed comfortable rows + SCROLL (wheel / drag / ▲▼).
    var top=42, n=order.length, rowH=30, cardH=25, y=top;
    order.forEach(function(w){
      var cy=y+rowH/2;
      self.add.text(22,cy,'W'+w,{fontFamily:'"Press Start 2P"',fontSize:'8px',color:'#66ccff'}).setOrigin(0,.5);
      worlds[w].forEach(function(o,c){
        var x=52+c*138, isBoss=!!o.l.boss, isVip=!!o.l.vip;
        var sub=(o.l.sub||''); if(sub.length>17) sub=sub.slice(0,16)+'…';
        var allowed=nqWorldAllowed(o.l);
        var box=self.add.rectangle(x,cy,130,cardH,isVip?0x2a2008:(isBoss?0x351033:0x141a2e),1).setStrokeStyle(2,allowed?(isVip?0xffd23f:(isBoss?0xff3860:0x2a4a6a)):(isVip?0x8a6a1a:0x3a3a46)).setOrigin(0,.5).setInteractive({useHandCursor:true});
        if(isVip&&c===0) self.add.text(22,cy+9,'👑',{fontSize:'8px'}).setOrigin(0,.5);
        // 10+ worlds shrink the rows below what two stacked text lines can fit — go single-line there
        var oneLine=cardH<20;
        var t1=self.add.text(x+8,oneLine?cy:cy-cardH*0.24,(allowed?'':'🔒 ')+o.l.name+(oneLine?(' '+(isBoss?'★ ':'')+sub):''),{fontFamily:UIFONT,fontStyle:'bold',fontSize:oneLine?'10px':'9px',color:allowed?(isBoss?'#ff9ec0':'#ffffff'):'#8a8a98',resolution:UIRES}).setOrigin(0,.5);
        var t2=oneLine?null:self.add.text(x+8,cy+cardH*0.27,(isBoss?'★ ':'')+sub,{fontFamily:UIFONT,fontStyle:'bold',fontSize:'11px',color:allowed?(isBoss?'#ffd6e6':'#eef2ff'):'#6e6e7c',resolution:UIRES}).setOrigin(0,.5);
        if(!allowed){ box.setAlpha(.55); t1.setAlpha(.75); if(t2) t2.setAlpha(.6); }
        var go=allowed
          ? function(){ self.scene.start('Game',{level:o.i,score:0,lives:3}); }
          : function(){ try{ if(window.__NQ_OPENPREMIUM) window.__NQ_OPENPREMIUM(); }catch(e){} };   // locked → open the premium panel (verify wallet / buy NORMIE)
        box.on('pointerup',function(p){ if(p.getDistance()<12) go(); });   // pointerup + drag guard: a scroll-drag over a card must not launch it
        box.on('pointerover',function(){ box.setFillStyle(isBoss?0x4a1848:0x1e2842,1); });
        box.on('pointerout',function(){ box.setFillStyle(isBoss?0x351033:0x141a2e,1); });
      });
      y+=rowH;
    });
    // SCROLL: wheel, touch-drag anywhere, or ▲▼ — clamped to the content height. Everything
    // scrolls together (scrollFactor-0 pinning misplaces under this zoomed/centered camera —
    // the footer floated mid-screen; don't reintroduce it). Footer sits below the last row.
    var contentBottom=y+6, maxOff=Math.max(0, contentBottom+16-H);
    var cam=this.cameras.main, baseY=cam.scrollY, off=0;
    var setOff=function(v){ off=Phaser.Math.Clamp(v,0,maxOff); cam.scrollY=baseY+off; };
    if(maxOff>0){
      this.input.on('wheel',function(p,over,dx,dy){ setOff(off+dy*0.4); });
      this.input.on('pointermove',function(p){ if(p.isDown) setOff(off-(p.y-p.prevPosition.y)/cam.zoom); });
      this.input.keyboard.on('keydown-DOWN',function(){ setOff(off+40); });
      this.input.keyboard.on('keydown-UP',function(){ setOff(off-40); });
      this.add.text(W-14,top-6,'▼ scroll for more',{fontFamily:UIFONT,fontStyle:'600',fontSize:'10px',color:'#ffb43a',resolution:UIRES}).setOrigin(1,.5);
    }
    this.add.text(W/2,contentBottom+8,'in a level: press L to return here  ·  tap any card to play',{fontFamily:UIFONT,fontStyle:'600',fontSize:'10px',color:'#a7b2dc',resolution:UIRES}).setOrigin(.5);
    try{ if(typeof window!=='undefined') window.__NQ_LEVEL='level-select'; }catch(e){}
  }
});

