    k.setCollideWorldBounds(true); k.dir=-1; k.invuln=true; k.setDepth(7);
    var bg2=this.addGlow(k,0x2effa0,5); if(bg2) this.tweens.add({targets:bg2,outerStrength:12,duration:520,yoyo:true,repeat:-1,ease:'Sine.inOut'});
