// The NORMIE PRINCESS — Normie art + a drawn gold crown, composited once into a canvas texture.
// Not new art: it IS the brand mascot (crowned), so no external asset needed.
function makePrincessTex(scene){
  if(scene.textures.exists('princess')) return;
  try{
    var src=scene.textures.get('normie').getSourceImage();
    var w=src.width, h=src.height, crownH=Math.ceil(h*0.14);
    var cv=scene.textures.createCanvas('princess', w, h+crownH), ctx=cv.getContext();
    ctx.drawImage(src, 0, crownH);
    var cw=Math.ceil(w*0.4), cx0=Math.ceil(w*0.3), u=Math.max(2, Math.floor(crownH/4));
    ctx.fillStyle='#ffd23f';
    ctx.fillRect(cx0, crownH-u, cw, u);
    [0, 0.5, 1].forEach(function(f){ var px=cx0+Math.floor((cw-u)*f); ctx.fillRect(px, crownH-u*3, u, u*2); });
    ctx.fillStyle='#ff5a8a'; ctx.fillRect(cx0+Math.floor(cw/2-u/2), Math.max(0,crownH-u*2), u, u);
    cv.refresh();
  }catch(e){}
}
