var WorldClear=new Phaser.Class({ Extends:Phaser.Scene,
  initialize:function(){ Phaser.Scene.call(this,{key:'WorldClear'}); },
  init:function(d){ d=d||{}; this.nextLevel=d.next||0; this.score=d.score||0; this.lab=d.lab; this.cfg=WORLD_CLEARS[this.nextLevel]; },
  create:function(){
    var self=this, cx=W/2, cfg=this.cfg;
    this.t0=0; this.phase=0; this.done=false; this.hillOff=0; this._pp=false;
    if(!cfg){ this.goNext(); return; }   // no entry for this level -> pass straight through
    this.cameras.main.setZoom(2).centerOn(W/2,H/2);
    SFX.clear();
    // --- Phase 0: CELEBRATION — fireworks over the defeated boss + triumphant Normie ---
    this.p1=this.add.container(0,0);
    this.p1.add(this.add.rectangle(cx,H/2,W,H,cfg.bg));
    var b=this.add.image(cx+52,148,cfg.boss.img); b.setScale(cfg.boss.scale/b.height); b.setAngle(cfg.boss.angle); b.setAlpha(.92);
    if(cfg.boss.tint) b.setTint(cfg.boss.tint); this.p1.add(b);
    var hero=this.add.image(cx-44,132,'normie'); hero.setScale(84/hero.height); this.p1.add(hero);
    this.tweens.add({targets:hero,y:126,duration:650,yoyo:true,repeat:-1,ease:'Sine.inOut'});
    if(this.renderer.type===Phaser.WEBGL){ try{ hero.postFX.addGlow(0xffd23f,1.2,0,false,0.1,16); }catch(e){} }
    this.p1.add(this.add.text(cx,46,cfg.title,{fontFamily:'"Press Start 2P"',fontSize:'13px',color:cfg.color,align:'center',wordWrap:{width:W-30}}).setOrigin(.5));
    this.p1.add(this.add.text(cx,72,'WORLD '+cfg.world+' CLEARED',{fontFamily:'"Press Start 2P"',fontSize:'9px',color:'#ffd23f'}).setOrigin(.5));
    this.p1.add(this.add.text(cx,208,'SCORE  '+this.score,{fontFamily:'"Press Start 2P"',fontSize:'11px',color:'#ffffff'}).setOrigin(.5));
    // fireworks: spark bursts popping across the top of the tableau while the celebration runs
    var tints=[0xffd23f,0x3dff6e,0x66ddff,0xff8adf,0xffffff];
    this.time.addEvent({ delay:360, loop:true, callback:function(){
      if(self.phase!==0||self.done) return;
      var x=40+Math.random()*(W-80), y=28+Math.random()*104, tn=tints[(Math.random()*tints.length)|0];
      var e=self.add.particles(x,y,'spark',{speed:{min:40,max:150},lifespan:520,scale:{start:1.2,end:0},tint:tn,emitting:false,blendMode:'ADD'}).setDepth(30);
      e.explode(14); self.time.delayedCall(620,function(){ e.destroy(); });
    }});
    // --- Phase 1: TRAVELING page — next world's palette + story beat + crypto-term card ---
    this.p2=this.add.container(0,0).setVisible(false);
    var th=THEMES[cfg.theme]||THEMES[0];
    var g=this.add.graphics(); g.fillGradientStyle(th.sky1,th.sky1,th.sky2,th.sky2,1); g.fillRect(0,0,W,H); this.p2.add(g);
    this.p2.add(this.add.circle(W-64,40,20,0xffe08a).setAlpha(.5));
    this.hillG=this.add.graphics(); this.p2.add(this.hillG); this.hillCol=th.hill;
    this.runner=this.add.image(88,H-40,'nrun1'); this.runner.setScale(38/this.runner.height); this.p2.add(this.runner);
    if(this.renderer.type===Phaser.WEBGL){ try{ this.runner.postFX.addGlow(0x66ccff,1,0,false,0.1,12); }catch(e){} }
    this.p2.add(this.add.text(cx,24,'NOW TRAVELING',{fontFamily:'"Press Start 2P"',fontSize:'8px',color:'#b6bfe0'}).setOrigin(.5));
    this.p2.add(this.add.text(cx,42,cfg.dest,{fontFamily:'"Press Start 2P"',fontSize:'12px',color:cfg.color,align:'center',wordWrap:{width:W-24}}).setOrigin(.5));
    this.p2.add(this.add.text(cx,62,cfg.story,{fontFamily:UIFONT,resolution:UIRES,fontSize:'11px',color:'#eef2ff',align:'center',lineSpacing:2,wordWrap:{width:W-90}}).setOrigin(.5,0));
    var ty=134;   // crypto-term teaching card
    this.p2.add(this.add.rectangle(cx,ty+24,W-84,56,0x0d0b1e,0.82).setStrokeStyle(2,0xffd23f));
    this.p2.add(this.add.text(cx,ty+8,'CRYPTO TERM: '+cfg.term.name,{fontFamily:'"Press Start 2P"',fontSize:'8px',color:'#ffd23f',align:'center',wordWrap:{width:W-104}}).setOrigin(.5));
    this.p2.add(this.add.text(cx,ty+20,cfg.term.def,{fontFamily:UIFONT,resolution:UIRES,fontSize:'10px',color:'#d6d1ec',align:'center',lineSpacing:1,wordWrap:{width:W-110}}).setOrigin(.5,0));
    if(cfg.nostalgia) this.p2.add(this.add.text(cx,H-68,'★ '+cfg.nostalgia+' ★',{fontFamily:UIFONT,resolution:UIRES,fontSize:'10px',color:'#8f89b8',align:'center',wordWrap:{width:W-60}}).setOrigin(.5));
    this.drawHills();
    this.cont=this.add.text(cx,H-11,'TAP TO CONTINUE  ▶',{fontFamily:'"Press Start 2P"',fontSize:'9px',color:'#3dff6e'}).setOrigin(.5).setDepth(40);
    var adv=function(){ if(self.done) return; if(self.phase===0){ self.t0=self.time.now-3300; } else { self.goNext(); } };
    this.input.on('pointerdown',adv); this.input.keyboard.on('keydown',adv); this.adv=adv;
  },
  goNext:function(){ if(this.done) return; this.done=true;
    if(typeof BRIEFINGS!=='undefined' && BRIEFINGS[this.nextLevel]) this.scene.start('Briefing',{next:this.nextLevel,score:this.score,lab:this.lab});
    else this.scene.start('Game',{level:this.nextLevel,score:this.score,lives:3,lab:this.lab}); },
  drawHills:function(){ var d=this.hillG; if(!d) return; d.clear();
    d.fillStyle(this.hillCol,1); for(var i=-1;i<5;i++){ d.fillCircle(i*150-(this.hillOff%150)+75,H-12,60); }
    d.fillStyle(0x0a0813,0.35); d.fillRect(0,H-22,W,22); },
  update:function(){
    if(this.done) return;
    if(!this.t0){ this.t0=this.time.now; return; }   // capture start on the first real tick
    var t=this.time.now-this.t0;
    if(this.phase===1 && this.runner){
      var k=(Math.floor(this.time.now/110)%2)?'nrun2':'nrun1'; if(this.runner.texture.key!==k) this.runner.setTexture(k).setScale(38/this.runner.height);
      this.runner.y=(H-40)+Math.sin(this.time.now/90)*2;
      this.hillOff+=1.7; this.drawHills();
    }
    if(this.phase===0 && t>3300){ this.phase=1; this.p1.setVisible(false); this.p2.setVisible(true); }
    if(this.cont) this.cont.setAlpha(0.4+0.6*Math.abs(Math.sin(this.time.now/300)));
    // controller: any button press advances (edge-triggered; grace so the boss-kill press can't skip)
    var press=false;
    try{ var ps=(navigator.getGamepads?navigator.getGamepads():[]); for(var i=0;i<ps.length;i++){ var gp=ps[i]; if(!gp) continue;
      var B=gp.buttons||[]; for(var j=0;j<B.length;j++){ if(B[j]&&(B[j].pressed||B[j].value>0.5)){ press=true; break; } } if(press) break; }}catch(e){}
    if(press && !this._pp && t>600 && this.adv) this.adv();
    this._pp=press;
    if(t>14000) this.goNext();   // safety auto-advance — can never soft-lock
  }
});

