var NQGAME=new Phaser.Game({
  // Render at 2x internal resolution (each scene camera zooms 2x, so the world view is
  // unchanged but the backing store is 960x540 -> crisp, not blocky, when displayed big).
  type:Phaser.AUTO, parent:'screen', width:W*2, height:H*2, pixelArt:true, backgroundColor:'#0a0813', roundPixels:true,
  scale:{ mode:Phaser.Scale.FIT, autoCenter:Phaser.Scale.CENTER_BOTH },
  physics:{ default:'arcade', arcade:{ gravity:{y:900}, debug:false } },
  scene:[Boot,Title,LevelSelect,Controls,Gate,Game,Over,Win,WorldClear,Briefing,VipPitch]
});
// Global "jump to LEVEL SELECT" hook — works from ANY scene (title, game, over, win), so the
// reliable DOM "≡ Levels" button is never a dead end. Stops whatever's running, then starts it.
try{ if(typeof window!=='undefined') window.__NQ_TOLEVELS=function(){ try{
  try{ if(window.NQLB&&window.NQLB.abandonRun) window.NQLB.abandonRun(); }catch(e){}   // leaving mid-run = abandon the leaderboard run token
  NQGAME.scene.getScenes(true).forEach(function(sc){ var k=sc.sys&&sc.sys.settings&&sc.sys.settings.key; if(k&&k!=='LevelSelect') NQGAME.scene.stop(k); });
  NQGAME.scene.start('LevelSelect');
}catch(e){} }; }catch(e){}
// LAB toolkit: start any level from ANY scene (title, level select, mid-run) — the per-scene
// __NQ_WARP hook only exists once a Game scene is live, which left the warp dead on the title.
// Setup-lane only; passes lab:1 so the owner's bench bypasses the tier gate.
try{ if(typeof window!=='undefined') window.__NQ_STARTLEVEL=function(idx,x){ try{
  if(!window.__NQ_SETUP) return;
  NQGAME.scene.getScenes(true).forEach(function(sc){ var k=sc.sys&&sc.sys.settings&&sc.sys.settings.key; if(k) NQGAME.scene.stop(k); });
  NQGAME.scene.start('Game',{level:Math.max(0,Math.floor(idx)||0),score:0,lives:3,spawnX:(x>0?x:undefined),lab:1});
  try{ sessionStorage.removeItem('nqPendingWarp'); }catch(e){}   // warp landed — clear the reload-resume note
}catch(e){ try{ window.__NQ_WARPERR=String((e&&e.stack)||e); }catch(_){} } }; }catch(e){}
// LAB warp survives a tab reload (Phantom/iOS silently evicts+reloads tabs mid-gesture — the
// native <select> picker backgrounds the page, and a reload there loses the warp and boots you
// back to 1-1). The DOM GO button stores its target in sessionStorage BEFORE warping; a fresh
// boot in the setup lane finds it here and resumes the warp once the Boot scene is done.
try{ if(typeof window!=='undefined' && window.__NQ_SETUP){
  var _pw=null; try{ _pw=JSON.parse(sessionStorage.getItem('nqPendingWarp')||'null'); }catch(e){}
  if(_pw && typeof _pw.i==='number' && Date.now()-_pw.t<120000){
    var _pwTries=0, _pwIv=setInterval(function(){ _pwTries++;
      try{ var act=NQGAME.scene.getScenes(true).map(function(sc){ return sc.sys&&sc.sys.settings&&sc.sys.settings.key; });
        if(act.length && act.indexOf('Boot')<0){ clearInterval(_pwIv); window.__NQ_STARTLEVEL(_pw.i,_pw.x); } }catch(e){}
      if(_pwTries>160) clearInterval(_pwIv);   // ~40s cap, then give up quietly
    },250);
  } else if(_pw){ try{ sessionStorage.removeItem('nqPendingWarp'); }catch(e){} }
} }catch(e){}
// LAB toolkit: scene observability for the headless test harness — active scene keys + the
// visible text objects (so a script can assert "WorldClear is showing THE RUG KING FALLS!").
// Setup-lane only, read-only.
try{ if(typeof window!=='undefined') window.__NQ_SCENES=function(){ try{
  if(!window.__NQ_SETUP) return null;
  var out=[]; NQGAME.scene.getScenes(true).forEach(function(sc){
    var k=sc.sys&&sc.sys.settings&&sc.sys.settings.key, txt=[];
    try{ sc.children.list.forEach(function(o){ if(o.text) txt.push(o.text); if(o.list) o.list.forEach(function(c){ if(c.text&&c.parentContainer&&c.parentContainer.visible) txt.push(c.text); }); }); }catch(e){}
    out.push({key:k,text:txt.join(' | ')});
  }); return out;
}catch(e){ return [{key:'err',text:String(e)}]; } }; }catch(e){}
// LAB toolkit: level list for the warp dropdown (name + width so the panel can bound the x input).
try{ if(typeof window!=='undefined') window.__NQ_LEVELS_LIST=LEVELS.map(function(l,i){ return {i:i,name:l.name,sub:l.sub||'',width:l.width||5000}; }); }catch(e){}
// Real world count for the setup-lane leaderboard chips (same formula the Win scenes use).
